fn ensure_usable_cors_rules(&self) {
    if self.allow_credentials.is_true() {
        assert!(
            !self.allow_headers.is_wildcard(),
            "Invalid CORS configuration: Cannot combine `Access-Control-Allow-Credentials: true` \
             with `Access-Control-Allow-Headers: *`"
        );

        assert!(
            !self.allow_methods.is_wildcard(),
            "Invalid CORS configuration: Cannot combine `Access-Control-Allow-Credentials: true` \
             with `Access-Control-Allow-Methods: *`"
        );

        assert!(
            !self.allow_origin.is_wildcard(),
            "Invalid CORS configuration: Cannot combine `Access-Control-Allow-Credentials: true` \
             with `Access-Control-Allow-Origin: *`"
        );

        assert!(
            !self.expose_headers.is_wildcard(),
            "Invalid CORS configuration: Cannot combine `Access-Control-Allow-Credentials: true` \
             with `Access-Control-Expose-Headers: *`"
        );
    }
}

let app = Router::new()
        .leptos_routes(&leptos_options, routes, {
            let leptos_options = leptos_options.clone();
            move || shell(leptos_options.clone())
        })
        .fallback(leptos_axum::file_and_error_handler_with_context(
            move || {
                // if you want to add custom headers to the static file handler response,
                // you can do that by providing `ResponseOptions` via context
                let opts = use_context::<leptos_axum::ResponseOptions>()
                    .unwrap_or_default();
                opts.insert_header(
                    HeaderName::from_static("cross-origin-opener-policy"),
                    HeaderValue::from_static("same-origin"),
                );
                opts.insert_header(
                    HeaderName::from_static("cross-origin-embedder-policy"),
                    HeaderValue::from_static("require-corp"),
                );
                provide_context(opts);
            },
            shell,
        ))
        .with_state(leptos_options);

pub fn finish(mut self) -> Schema<Query, Mutation, Subscription> {
    // federation
    if self.registry.enable_federation || self.registry.has_entities() {
        self.registry.create_federation_types();
    }

    Schema(Arc::new(SchemaInner {
        validation_mode: self.validation_mode,
        query: self.query,
        mutation: self.mutation,
        subscription: self.subscription,
        complexity: self.complexity,
        depth: self.depth,
        recursive_depth: self.recursive_depth,
        max_directives: self.max_directives,
        max_aliases: self.max_aliases,
        extensions: self.extensions,
        env: SchemaEnv(Arc::new(SchemaEnvInner {
            registry: self.registry,
            data: self.data,
            custom_directives: self.custom_directives,
        })),
    }))
}

#[doc(hidden)]
    #[inline]
    pub fn strip_to_hyper(&mut self) -> hyper::Response<ResBody> {
        // Flush any cookies onto `self.headers` *before* we transfer them to the new
        // hyper response so the tower-compat path does not silently lose `Set-Cookie`.
        #[cfg(feature = "cookie")]
        Self::flush_cookies_into(&mut self.headers, &mut self.cookies);

        let mut res = hyper::Response::new(std::mem::take(&mut self.body));
        *res.extensions_mut() = std::mem::take(&mut self.extensions);
        *res.headers_mut() = std::mem::take(&mut self.headers);
        if let Some(status) = self.status_code {
            // Default to a 404 if no response code was set
            *res.status_mut() = status;
        }

        res
    }

